class FenwickTree:
    def __init__(self, size):
        self.n = size
        self.tree = [0] * (self.n + 1)

    def update(self, idx, delta):
        while idx <= self.n:
            self.tree[idx] += delta
            idx += idx & -idx

    def query(self, idx):
        res = 0
        while idx > 0:
            res += self.tree[idx]
            idx -= idx & -idx
        return res

    def range_query(self, l, r):
        return self.query(r) - self.query(l - 1)


def solve(nums: list[int], queries: list[list[int]]) -> list[int]:
    def get_depth(x):
        d = 0
        while True:
            if x == 1:
                return d
            x = bin(x).count('1')
            d += 1

    n = len(nums)
    ft = [FenwickTree(n) for _ in range(6)]

    for i in range(n):
        x = nums[i]
        d = get_depth(x)
        if 0 <= d <= 5:
            ft[d].update(i + 1, 1)

    answer = []
    for q in queries:
        if q[0] == 1:
            l, r, k = q[1], q[2], q[3]
            res = ft[k].range_query(l + 1, r + 1)
            answer.append(res)
