            idx, val = q[1], q[2]
            old_val = nums[idx]
            old_d = get_depth(old_val)
            if 0 <= old_d <= 5:
                ft[old_d].update(idx + 1, -1)
            nums[idx] = val
            new_d = get_depth(val)
            if 0 <= new_d <= 5:
                ft[new_d].update(idx + 1, 1)
    return answer
